/**
 * Custom createDeepAgent that mirrors the SDK's createDeepAgent but allows
 * injecting custom middleware into the subagent middleware stack.
 *
 * The SDK's createDeepAgent only appends custom middleware to the main agent;
 * subagents get a hardcoded middleware stack. This version accepts an additional
 * `subagentMiddleware` option so middleware like contextOverflowBridgeMiddleware
 * can propagate to subagents.
 */
import { Runnable } from '@langchain/core/runnables';
import { SystemMessage } from '@langchain/core/messages';
import {
  createAgent,
  createMiddleware,
  todoListMiddleware,
  anthropicPromptCachingMiddleware,
  humanInTheLoopMiddleware,
  type AgentMiddleware,
} from 'langchain';
import {
  createFilesystemMiddleware,
  createSubAgentMiddleware,
  createSummarizationMiddleware,
  createPatchToolCallsMiddleware,
  createSkillsMiddleware,
  createMemoryMiddleware,
  StateBackend,
  type CreateDeepAgentParams,
  type SubAgent,
  type CompiledSubAgent,
} from 'deepagents';

const BASE_PROMPT =
  'In order to complete the objective that the user asks of you, you have access to a number of standard tools.';

/**
 * Detect whether a model is an Anthropic model.
 * Used to gate Anthropic-specific prompt caching optimizations.
 */
function isAnthropicModel(model: any): boolean {
  if (typeof model === 'string') {
    if (model.includes(':')) return model.split(':')[0] === 'anthropic';
    return model.startsWith('claude');
  }
  if (model.getName?.() === 'ConfigurableModel')
    return model._defaultConfig?.modelProvider === 'anthropic';
  return model.getName?.() === 'ChatAnthropic';
}

/**
 * Middleware that adds cache_control breakpoint to the last system message block.
 * Replicated from the SDK's internal createCacheBreakpointMiddleware.
 */
function createCacheBreakpointMiddleware() {
  return createMiddleware({
    name: 'CacheBreakpointMiddleware',
    wrapModelCall(request, handler) {
      const existingContent = (request as any).systemMessage?.content;
      const existingBlocks =
        typeof existingContent === 'string'
          ? [{ type: 'text' as const, text: existingContent }]
          : Array.isArray(existingContent)
            ? [...existingContent]
            : [];
      if (existingBlocks.length === 0) return handler(request);
      existingBlocks[existingBlocks.length - 1] = {
        ...existingBlocks[existingBlocks.length - 1],
        cache_control: { type: 'ephemeral' },
      } as any;
      return handler({
        ...request,
        systemMessage: new SystemMessage({ content: existingBlocks }),
      } as any);
    },
  });
}

export interface CustomDeepAgentParams extends CreateDeepAgentParams {
  /**
   * Additional middleware to inject into the subagent middleware stack.
   * These run AFTER the default subagent middleware (todo, filesystem,
   * summarization, prompt caching, patch tool calls) but BEFORE
   * any per-subagent middleware.
   *
   * Use this to propagate middleware like contextOverflowBridgeMiddleware
   * that the SDK's createDeepAgent doesn't forward to subagents.
   */
  extraSubagentMiddleware?: AgentMiddleware[];
}

export function createCustomDeepAgent(params: CustomDeepAgentParams = {}) {
  const {
    model = 'claude-sonnet-4-5-20250929',
    tools = [],
    systemPrompt,
    middleware: customMiddleware = [],
    subagents = [],
    responseFormat,
    contextSchema,
    checkpointer,
    store,
    backend,
    interruptOn,
    name,
    memory,
    skills,
    extraSubagentMiddleware = [],
  } = params;

  const anthropicModel = isAnthropicModel(model);

  // Build system prompt
  const finalSystemPrompt = new SystemMessage({
    content: systemPrompt
      ? typeof systemPrompt === 'string'
        ? [{ type: 'text' as const, text: `${systemPrompt}\n\n${BASE_PROMPT}` }]
        : [
            { type: 'text' as const, text: BASE_PROMPT },
            ...(typeof (systemPrompt as SystemMessage).content === 'string'
              ? [{ type: 'text' as const, text: (systemPrompt as SystemMessage).content as string }]
              : ((systemPrompt as SystemMessage).content as any[])),
          ]
      : [{ type: 'text' as const, text: BASE_PROMPT }],
  });

  // Backend configuration
  const filesystemBackend = backend
    ? backend
    : (config: any) => new StateBackend(config);

  // Skills middleware
  const skillsMiddlewareArray =
    skills != null && skills.length > 0
      ? [createSkillsMiddleware({ backend: filesystemBackend, sources: skills })]
      : [];

  // Memory middleware
  const memoryMiddlewareArray =
    memory != null && memory.length > 0
      ? [
          createMemoryMiddleware({
            backend: filesystemBackend,
            sources: memory,
            addCacheControl: anthropicModel,
          }),
        ]
      : [];

  // Process subagents: add SkillsMiddleware for those with their own skills
  const processedSubagents = (subagents as (SubAgent | CompiledSubAgent)[]).map(
    (subagent) => {
      if (Runnable.isRunnable(subagent)) return subagent;
      if (
        !('skills' in subagent) ||
        (subagent as SubAgent).skills?.length === 0
      )
        return subagent;
      const subagentSkillsMiddleware = createSkillsMiddleware({
        backend: filesystemBackend,
        sources: (subagent as SubAgent).skills ?? [],
      });
      return {
        ...subagent,
        middleware: [
          subagentSkillsMiddleware,
          ...((subagent as SubAgent).middleware || []),
        ],
      };
    },
  );

  /**
   * Default middleware for subagents.
   * KEY DIFFERENCE: extraSubagentMiddleware is injected here so that
   * middleware like contextOverflowBridgeMiddleware propagates to subagents.
   */
  const subagentMiddleware: AgentMiddleware[] = [
    todoListMiddleware(),
    createFilesystemMiddleware({ backend: filesystemBackend }),
    createSummarizationMiddleware({ model, backend: filesystemBackend }),
    anthropicPromptCachingMiddleware({
      unsupportedModelBehavior: 'ignore',
      minMessagesToCache: 1,
    }),
    createPatchToolCallsMiddleware(),
    ...extraSubagentMiddleware,
  ];

  return createAgent({
    model,
    systemPrompt: finalSystemPrompt,
    tools,
    middleware: [
      // Built-in middleware stack
      todoListMiddleware(),
      createFilesystemMiddleware({ backend: filesystemBackend }),
      createSubAgentMiddleware({
        defaultModel: model,
        defaultTools: tools,
        defaultMiddleware: [
          ...subagentMiddleware,
          ...(anthropicModel ? [createCacheBreakpointMiddleware()] : []),
        ],
        generalPurposeMiddleware: [
          ...subagentMiddleware,
          ...skillsMiddlewareArray,
          ...(anthropicModel ? [createCacheBreakpointMiddleware()] : []),
        ],
        defaultInterruptOn: interruptOn,
        subagents: processedSubagents,
        generalPurposeAgent: true,
      }),
      createSummarizationMiddleware({ model, backend: filesystemBackend }),
      anthropicPromptCachingMiddleware({
        unsupportedModelBehavior: 'ignore',
        minMessagesToCache: 1,
      }),
      createPatchToolCallsMiddleware(),
      // Conditional middleware
      ...skillsMiddlewareArray,
      ...(anthropicModel ? [createCacheBreakpointMiddleware()] : []),
      ...memoryMiddlewareArray,
      ...(interruptOn
        ? [humanInTheLoopMiddleware({ interruptOn })]
        : []),
      // User's custom middleware (runs innermost)
      ...(customMiddleware as AgentMiddleware[]),
    ],
    ...(responseFormat != null && { responseFormat }),
    contextSchema,
    checkpointer,
    store,
    name,
  } as any).withConfig({
    recursionLimit: 1e4,
    metadata: { ls_integration: 'deepagents' },
  });
}

